import{c as t,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"The Neuron — 2026-05-05","description":"","frontmatter":{"title":"The Neuron — 2026-05-05","date":"2026-05-05T00:00:00.000Z","source":"The Neuron","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-05-the-neuron.md","filePath":"research/ai-news/2026-05/2026-05-05-the-neuron.md","lastUpdated":1779898012000}'),n={name:"research/ai-news/2026-05/2026-05-05-the-neuron.md"};function s(i,e,m,c,d,p){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="🧠-the-neuron-—-2026-05-05" tabindex="-1">🧠 The Neuron — 2026-05-05 <a class="header-anchor" href="#🧠-the-neuron-—-2026-05-05" aria-label="Permalink to &quot;🧠 The Neuron — 2026-05-05&quot;">​</a></h1><blockquote><p>面向非技術讀者的 AI 日報，3 分鐘讀完 來源：<a href="https://rss.beehiiv.com/feeds/N4eCstxvgX.xml" target="_blank" rel="noreferrer">The Neuron</a></p></blockquote><hr><h2 id="😺-mayo-s-ai-spotted-cancer-3-years-before-doctors-did" tabindex="-1"><a href="https://www.theneurondaily.com/p/mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">😺 Mayo&#39;s AI spotted cancer 3 years before doctors did</a> <a class="header-anchor" href="#😺-mayo-s-ai-spotted-cancer-3-years-before-doctors-did" aria-label="Permalink to &quot;[😺 Mayo&#39;s AI spotted cancer 3 years before doctors did](https://www.theneurondaily.com/p/mayo-s-ai-spotted-cancer-3-years-before-doctors-did)&quot;">​</a></h2><p><em>🧠 The Neuron | 2026-05-05</em></p><p><a href="https://www.arm.com/company/arm-everywhere?utm_source=neuron&amp;utm_medium=display&amp;utm_content=banner_static_logo_more&amp;utm_campaign=mk35_cloudai_cloud-ai_thirdparty_mediabuy_na" target="_blank" rel="noreferrer"></a></p><p>Welcome, humans.</p><p>We hope you like sriracha in your Earl Gray because we’ve got some spicy tea for y’all today:</p><p><a href="https://www.nbcnews.com/tech/tech-news/musk-lawyer-hammers-openai-co-founder-30-billion-stake-rcna343518?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">Greg Brockman took the stand</a> at the Musk v. Altman trial yesterday and confirmed his personal OpenAI stake is now worth nearly ~$30 billion. Not too shabby… But the star witness was not Brockman himself, but <a href="https://www.instagram.com/reel/DX8LUoutMiF/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">his journal</a>…</p><p>That’s right: Musk&#39;s lawyer read<a href="https://thenextweb.com/news/openai-trial-brockman-journals-nonprofit-settlement?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer"> Brockman&#39;s personal journal</a> aloud to the jury, including a 2017 entry asking himself &quot;Financially, what will take me to $1B?&quot; and another where Brockman described OpenAI&#39;s public commitment to its nonprofit mission as &quot;a lie.&quot;</p><p>Brockman&#39;s defense from the stand: these are hundreds of pages of stream-of-consciousness self-doubt, not some master plan. And just think, this was 2017, so before ChatGPT was good enough to actually conspire brainstorm with… wonder if these days Brockman does his scheming stream of consciousness self doubt journaling with GPT.</p><p>Meanwhile, John Gruber of Daring Fireball did some investigative journalism and<a href="https://daringfireball.net/2026/05/y_combinators_stake_in_openai?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer"> discovered</a> that Y Combinator quietly owns roughly 0.6% of OpenAI (worth ~$5B at the current $852B valuation), which could mean YC co-founders Paul Graham and partner Jessica Livingston have personal billions riding on Sam Altman keeping his job.</p><p>Gruber says Graham spent the last few weeks publicly defending Altman in that new “can we trust Sam Altman?”<a href="https://www.newyorker.com/magazine/2026/04/13/sam-altman-may-control-our-future-can-he-be-trusted?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer"> New Yorker piece</a> and on X; and per Gruber, he&#39;s<a href="https://daringfireball.net/2026/04/when_he_is_alive_and_not_after_he_is_dead?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer"> conspicuously stopped short</a> of ever actually calling Altman trustworthy or a man of integrity.</p><p>If only we had an impartial, totally unbiased, perhaps literally mechanical witness with absolutely nothing to gain to attest to Sam’s character once and for all… Wait, we’ve got it!</p><p>Picture Law and Order’s Jack McCoy: “Your Honor, the prosecution would like to call ChatGPT to the stand.” Who better to read someone’s chat logs into the record than the chatbot itself? Better hope you fixed those hallucinations fam!</p><p>Here’s what happened in AI today:</p><p>😺 Mayo + Harvard: AI just beat doctors at their hardest jobs.</p><p>📰 The White House quietly considers pre-release AI model vetting.</p><p>📰 Anthropic and OpenAI both signed PE joint ventures.</p><p>🍪 Cursor Team Kit ships the workflows Cursor devs use internally.</p><p>🎓 Use o1 / Claude as a &quot;second opinion&quot; before big decisions.</p><p>…and a <a href="https://theneuron.ai/explainer-articles/around-the-horn-digest-everything-that-happened-in-ai-today-monday-may-4-2026?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">whole lot more that you can read about here</a>.</p><p>Hey: Want to reach 700,000+ AI-hungry readers? <a href="https://info.technologyadvice.com/advertise-with-the-neuron?utm_source=www.theneurondaily.com&amp;utm_medium=referral&amp;utm_campaign=diffusion-models-are-coming-for-text-at-0-80-per-million-flat" target="_blank" rel="noreferrer">Advertise with us!</a><a href="https://info.technologyadvice.com/advertise-with-the-neuron?utm_source=www.theneurondaily.com&amp;utm_medium=referral&amp;utm_campaign=diffusion-models-are-coming-for-text-at-0-80-per-million-flat" target="_blank" rel="noreferrer"> </a></p><p>P.S: Love robots? We’re starting a new robotics newsletter! <a href="https://form.jotform.com/260897013570156?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">Sign up early here</a>.</p><p>😺 The Robot Will See You Now (And It&#39;s Already Better Than Your Doctor At Two Things)</p><p>Two peer-reviewed studies dropped this week showing AI now beats specialist physicians at the two hardest parts of medicine: catching invisible disease early, and triaging patients in the first uncertain minutes.</p><p>First up: <a href="https://www.nbcnews.com/health/cancer/ai-early-signs-pancreatic-cancer-before-tumors-develop-rcna343099?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">Mayo Clinic&#39;s REDMOD model</a> spotted pancreatic cancer up to three years before diagnosis (<a href="https://gut.bmj.com/content/early/2026/04/22/gutjnl-2025-337266?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">study</a>).</p><p>The team analyzed nearly 2,000 routine CT scans originally read as normal, including scans from patients later diagnosed with the disease.</p><p>REDMOD flagged 73% of those prediagnostic cancers, vs. 39% caught by specialist radiologists looking at the same images.</p><p>Median lead time: 16 months.</p><p>For scans taken more than two years pre-diagnosis, the AI was three times more sensitive than human experts.</p><p>This is a big deal. Pancreatic cancer kills most patients precisely because we catch it too late (<a href="https://gut.bmj.com/content/early/2026/04/22/gutjnl-2025-337266?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">13% five-year survival, 80% diagnosed at advanced stage</a>). REDMOD changes that math.</p><p>Next up: <a href="https://techcrunch.com/2026/05/03/in-harvard-study-ai-offered-more-accurate-diagnoses-than-emergency-room-doctors/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">Harvard&#39;s Science paper on OpenAI&#39;s o1</a>, and admittedly older model, is fascinating. Researchers at Harvard, Beth Israel Deaconess, and Stanford ran six experiments pitting o1 against attending physicians (<a href="https://www.science.org/doi/10.1126/science.adz4433?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">study</a>).</p><p>The headline test: 76 real Beth Israel ER cases where the model got 67% of triage diagnoses exactly or near-exactly right.</p><p>The two attendings scored 55% and 50%.</p><p>Blinded reviewers couldn&#39;t tell which diagnoses came from the humans.</p><p>The gap was largest in the first minutes of triage, when information is sparse and stakes are highest.</p><p>Now, it’s worth noting: Both teams stopped short of recommending clinical deployment and called for prospective trials.</p><p>Why this matters: These studies test something harder than memorized medical knowledge (<a href="https://www.vox.com/health/487425/open-ai-chatgpt-diagnosis-symptoms-second-opinion-study?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">Vox notes</a> that &quot;knowing the diagnosis isn&#39;t treating the patient&quot;). They measure reasoning under uncertainty with incomplete information, which is, y’know, the actual hard part of medicine. AI cleared that bar twice in one week, on different problems. And this is far from frontier AI we’re talking about here, at least as far as the triaging study goes.</p><p>Our take: AI-assisted triage in under-resourced ERs just became a near-term policy question. &quot;Second opinion&quot; tools may become standard before major diagnoses (the way spell-check became standard before sending an email… at least for SOME of us).</p><p>Now, <a href="https://www.bostonglobe.com/2026/05/03/business/ai-diagnosis-emergency-department-patients-hospital/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">Medical AI liability frameworks are nowhere near ready</a>; but that&#39;s tomorrow&#39;s problem. Mayo&#39;s senior author Dr. Ajit Goenka put it cleanly: &quot;In a disease where we have been just wandering in darkness for decades, this is a milestone that shows us the finish line, but we still have to get to the finish line.&quot; I think we all want a little bit more news like this, right?</p><p>FROM OUR PARTNERS</p><p>A defining moment for AI compute</p><p><a href="https://www.arm.com/company/arm-everywhere?utm_source=neuron&amp;utm_medium=display&amp;utm_content=banner_static_logo_more&amp;utm_campaign=mk35_cloudai_cloud-ai_thirdparty_mediabuy_na" target="_blank" rel="noreferrer"></a></p><p>More than 50 companies are backing <a href="https://www.arm.com/company/arm-everywhere?utm_source=neuron&amp;utm_medium=display&amp;utm_content=banner_static_logo_more&amp;utm_campaign=mk35_cloudai_cloud-ai_thirdparty_mediabuy_na" target="_blank" rel="noreferrer">Arm’s</a> move into silicon — spanning cloud, chip design and software.</p><p>From AWS, Google and Microsoft to NVIDIA, Samsung, SK hynix and TSMC, the ecosystem signals a broader shift in how AI infrastructure is being built.</p><p>Rather than isolated components, the stack is becoming more tightly integrated — from architecture through to deployment.</p><p><a href="https://www.arm.com/company/arm-everywhere?utm_source=neuron&amp;utm_medium=display&amp;utm_content=banner_static_logo_more&amp;utm_campaign=mk35_cloudai_cloud-ai_thirdparty_mediabuy_na" target="_blank" rel="noreferrer">Explore how this is taking shape</a></p><p>🎓 AI Skill of the Day: Use GPT 5.5 / Claude as a &quot;Second Opinion&quot; Before Any Big Decision.</p><p>Today&#39;s Harvard study showed o1 (an older generation reasoning model from OpenAI) beating ER attendings most decisively in the first minutes of triage, when information is sparse and pressure is high.</p><p>Most workplace decisions look exactly like that: contract negotiations, hiring calls, architectural choices, budget approvals. The skill is feeding a reasoning model your conclusion plus your reasoning, then asking it to find what you missed.</p><p>Drop this into<a href="https://chatgpt.com/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer"> GPT 5.5 with reasoning on</a>,<a href="https://claude.ai/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer"> Claude Opus 4.7</a>, or<a href="https://gemini.google.com/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer"> Gemini 3.1 Pro</a></p><p>I&#39;ve concluded [DECISION] based on the following reasoning: [YOUR REASONING]. Before I commit, I want a structured second opinion. Please:</p><ol><li>Identify the strongest argument against my conclusion.</li><li>Generate three alternative hypotheses I may have missed.</li><li>List the specific evidence or scenarios that would shift your assessment in either direction.</li><li>Flag any assumptions in my reasoning that look load-bearing but aren&#39;t actually supported. Be direct. I&#39;m looking for the version of this analysis I&#39;d get from a sharp colleague who isn&#39;t trying to spare my feelings.</li></ol><p>The trick is forcing yourself to write out your reasoning before pasting. Half the value is in that step alone; the model just stress-tests the rest.</p><p>Total AI beginner? <a href="https://www.theneuron.ai/explainer-articles/everything-we-covered-in-our-ai-for-total-beginners-livestream-full-guide-with-timestamps/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">Start here</a> (<a href="https://www.youtube.com/live/QbFU0UNMVaU?si=skJsgUIDjKjAx3DU&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">goes with this video</a>).</p><p>Have a specific skill you want to learn? <a href="https://docs.google.com/forms/d/e/1FAIpQLSd_-hSXtB9ytR1HQrU85IJnJw233bNKptiGB5BZh9maPse1Eg/viewform?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">Request it here.</a></p><p>🍪 Treats to Try</p><p><a href="https://cursor.com/marketplace/cursor/cursor-team-kit?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">Cursor Team Kit</a> ships the internal CI watcher, code-review harness, deslop cleaner, and shipping workflows Cursor devs use themselves; runs locally, no third-party services —free to try.</p><p><a href="https://unity.com/features/ai?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">Unity AI</a> entered open beta with a project-aware in-editor agent (plus AI Gateway and MCP Server) trained on 20+ years of Unity practices that automates tasks, generates assets from designs, and drives Editor actions —free trial, then $10/month for Personal.</p><p><a href="https://vercel.com/blog/introducing-deepsec-find-and-fix-vulnerabilities-in-your-code-base?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">Vercel deepsec</a> is an open-source CLI (command line) security harness that runs pluggable coding agents in parallel sandboxes on your own infra (with your keys) to surface and validate vulnerabilities in large codebases with low false positives, free to try.</p><p><a href="https://kyutai.org/blog/2026-05-04-pocket-tts-multilingual?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">Pocket TTS</a> by Kyutai Labs runs open-source 100M-parameter text-to-speech models in six languages on your CPU in real time, no GPU required —free to try.</p><p><a href="https://saperly.com/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">Saperly</a> is the first phone carrier built for AI agents; provision a real number in seconds via any MCP-compatible agent for unified calling, SMS, and stable caller ID with audit trails —first number free for 30 days, then $2.50/month + usage.</p><p><a href="https://adaptive.ai/docs/passport?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">Adaptive Passport</a> lets your agent sign up for new accounts and acquire API keys, service credentials, and other requirements without you in the loop, covering 61+ services including FRED so the agent can build a continuously syncing economic-data model on its own, paid only rn.</p><p><a href="https://codex-pets.net/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did#/?sort=popular%7CCodex%20Pets" target="_blank" rel="noreferrer">Codex Pets</a> gives you an animated pixel companion that floats on your screen and pings you when OpenAI&#39;s Codex coding agent finishes a task or needs input, with a community gallery where you can install custom pets like Clippy or Goku in a single command (<a href="https://mashable.com/article/openai-introduce-ai-pet-companions-to-codex-app?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">Mashable</a>).</p><p>📰 Around the Horn</p><p><a href="https://x.com/AISafetyMemes/status/2051381199608729625?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer"></a></p><p><a href="https://www.nytimes.com/2026/05/04/technology/trump-ai-models.html?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">The Trump White House is quietly considering pre-release AI vetting</a> through a potential executive order forming a working group with tech executives, a sharp reversal of its deregulation stance prompted by cybersecurity concerns over Anthropic&#39;s Mythos model. (<a href="https://open.substack.com/pub/noahpinion/p/ais-big-messaging-pivot?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">good article on why</a>)</p><p><a href="https://techcrunch.com/2026/05/04/anthropic-and-openai-are-both-launching-joint-ventures-for-enterprise-ai-services/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">Anthropic and OpenAI both signed parallel PE joint ventures</a> on the same day; Anthropic CCO Paul Smith also spun out<a href="https://x.com/realpaulsmith/status/2051354602520404258?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer"> a $1.5B mid-market vehicle</a> backed by Blackstone, while OpenAI finalized<a href="https://www.bloomberg.com/news/articles/2026-05-04/openai-finalizes-10-billion-joint-venture-with-pe-firms-to-deploy-ai?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer"> a $10B partnership</a> with TPG, Brookfield, Advent, and Bain.</p><p><a href="https://www.cnbc.com/2026/05/04/bret-taylor-sierra-fundraise-openai.html?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">Bret Taylor&#39;s Sierra raised $950M Series E</a> at a $15.8B valuation, pushing total capital above $1B for its AI customer-service agents.</p><p><a href="https://www.reuters.com/legal/transactional/long-lake-buy-amex-corporate-travel-platform-63-billion-2026-05-04/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">Long Lake agreed to acquire Amex GBT for $6.3B</a> in an all-cash deal explicitly betting that AI will reshape corporate travel.</p><p><a href="https://www.404media.co/asu-atomic-ai-modules-arizona-state-university/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">Arizona State University deployed ASU Atomic</a>, an AI tool that auto-chops faculty lectures into learning modules without telling or asking the professors, who called the outputs inaccurate &quot;AI slop.&quot;</p><p><a href="https://mashable.com/article/oscars-ai-performances-eligibility%7CThe%20Academy%20of%20Motion%20Picture%20Arts%20and%20Sciences?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">The Academy of Motion Picture Arts and Sciences</a> ruled that AI-generated performances and screenplays are no longer eligible for Oscars, requiring acting roles to be &quot;demonstrably performed by humans with their consent&quot; — effectively shutting out synthetic stars like AI &quot;actress&quot; Tilly Norwood from awards contention.</p><p>FROM OUR PARTNERS</p><p>One brand built 30+ landing pages through Viktor without a single developer.</p><p><a href="https://ref.getviktor.com/vik-bh-mediabuy-secondary1?utm_campaign=&amp;_bhiiv=opp_a10e5164-ca13-4bf7-b0eb-89c3e02a0f8b_dc23507e&amp;bhcl_id=1ed44dfc-d904-4f49-8168-f75ea022eda7__" target="_blank" rel="noreferrer"></a></p><p>Each page mapped to a specific ad group. All deployed within hours. <a href="https://ref.getviktor.com/vik-bh-mediabuy-secondary1?utm_campaign=&amp;_bhiiv=opp_a10e5164-ca13-4bf7-b0eb-89c3e02a0f8b_dc23507e&amp;bhcl_id=1ed44dfc-d904-4f49-8168-f75ea022eda7__" target="_blank" rel="noreferrer">Viktor</a> wrote the code and shipped every one from a Slack message.</p><p>That same team has Viktor monitoring ad accounts across the portfolio and posting performance briefs before the day starts. One colleague. Always on. Across every account.</p><p>5,700+ teams. 3,000+ integrations.</p><p><a href="https://ref.getviktor.com/vik-bh-mediabuy-secondary1?utm_campaign=&amp;_bhiiv=opp_a10e5164-ca13-4bf7-b0eb-89c3e02a0f8b_dc23507e&amp;bhcl_id=1ed44dfc-d904-4f49-8168-f75ea022eda7__" target="_blank" rel="noreferrer">Start free. $100 in credits →</a></p><p>🐦 Tuesday Tweets:</p><p>Three from the weekend that earned their virality:</p><p><a href="https://x.com/justinskycak/status/2051035315083870526?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">Justin Skycak</a> (13,645 likes): &quot;Never underestimate how much time and effort you can waste by trying to automate a process you do not understand manually.&quot; Tape this above your IDE.</p><p><a href="https://x.com/sama/status/2050671161915371998?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">Sam Altman</a> (13,054 likes): &quot;i keep thinking i want the models to be cheaper/faster more than i want them to be smarter but it seems that just being smarter is still the most important thing.&quot; The whole AI industry&#39;s quarterly roadmap, right there.</p><p><a href="https://x.com/mcuban/status/2051291851185955289?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">Mark Cuban</a> (3,205 likes) on enterprise AI&#39;s biggest blocker: same question, different answers, every time. He frames the non-determinism as evidence against doomers since it proves the models clearly don&#39;t understand consequences.</p><p>A Cat’s Commentary</p><p>That’s all for now.</p><p>P.P.S: Love the newsletter, but only want to get it once per week? Don’t unsubscribe—<a href="https://www.theneurondaily.com/subscribe/f5596641-9099-4045-9641-731cd9fdcf90/preferences?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=mayo-s-ai-spotted-cancer-3-years-before-doctors-did" target="_blank" rel="noreferrer">update your preferences here</a>.</p><hr>',89)])])}const h=t(n,[["render",s]]);export{u as __pageData,h as default};
